pub(super) fn dispatch(
    engine: &MindLeak,
    name: &str,
    args: &Value,
) -> Option<Result<Value, String>> {
    match name {
        "graph_snapshot" => Some((|| {
            let seed = opt_str(args, "seed");
            let limit = opt_i64(args, "limit", 50).clamp(1, 500) as usize;
            let sub = engine
                .snapshot(seed.as_deref(), limit)
                .map_err(|e| e.to_string())?;
            Ok(text_result(&json!(sub)))
        })()),
        "prune_graph" => Some((|| {
            let outcome = engine.prune().map_err(|e| e.to_string())?;
            Ok(text_result(&json!(outcome)))
        })()),
        "graph_stats" => Some((|| {
            let (nodes, edges) = engine.counts().map_err(|e| e.to_string())?;
            Ok(text_result(
                &json!({ "nodes": nodes, "active_edges": edges }),
            ))
        })()),
        "export_graph" => Some((|| {
            let export = engine.export_graph().map_err(|e| e.to_string())?;
            Ok(text_result(&json!(export)))
        })()),
        "backup_database" => Some((|| {
            let path = req_str(args, "path")?;
            engine.backup_database(&path).map_err(|e| e.to_string())?;
            Ok(text_result(&json!({ "backed_up": true, "path": path })))
        })()),
        "reset_database" => Some((|| {
            let confirmation = req_str(args, "confirm")?;
            let outcome = engine
                .reset_database(&confirmation)
                .map_err(|e| e.to_string())?;
            Ok(text_result(&json!(outcome)))
        })()),
        "list_agents" => Some((|| {
            let agents = engine.list_agents().map_err(|e| e.to_string())?;
            Ok(text_result(&json!({ "agents": agents })))
        })()),
        "working_set" => Some((|| {
            let limit = args
                .get("limit")
                .and_then(Value::as_i64)
                .map(|value| value.clamp(1, 32) as usize);
            let items = engine.working_set(limit).map_err(|e| e.to_string())?;
            Ok(text_result(&json!({ "items": items })))
        })()),
        "evidence_for" => Some((|| {
            let agent = req_str(args, "agent_id")?;
            let started_at = required_i64(args, "started_at")?;
            let ended_at = required_i64(args, "ended_at")?;
            let evidence = engine
                .evidence_for(
                    opt_str(args, "task_id").as_deref(),
                    &agent,
                    started_at,
                    ended_at,
                )
                .map_err(|e| e.to_string())?;
            Ok(text_result(&json!(evidence)))
        })()),
        _ => None,
    }
}

#[cfg(test)]
mod tests {
    use super::super::tests::{call_ok, content_text};
    use super::super::{call, list};
    use mindleak_core::MindLeak;
    use serde_json::{json, Value};

    #[test]
    fn graph_stats_returns_counts() {
        let engine = MindLeak::open_in_memory().unwrap();
        call_ok(
            &engine,
            "ingest_file",
            json!({ "path": "a.rs", "content": "fn a() {}" }),
        );
        let text = content_text(&call_ok(&engine, "graph_stats", json!({})));
        assert!(text.contains("\"nodes\""));
        assert!(text.contains("\"active_edges\""));
    }

    #[test]
    fn working_set_uses_configured_agent_and_hard_cap() {
        let engine = MindLeak::open_in_memory()
            .unwrap()
            .with_working_set_size(1)
            .with_agent(Some("agent-a".to_string()));
        call_ok(
            &engine,
            "ingest_file",
            json!({ "path": "src/a.rs", "content": "fn a() {}" }),
        );
        call_ok(
            &engine,
            "ingest_file",
            json!({ "path": "src/b.rs", "content": "fn b() {}" }),
        );

        let result = call_ok(&engine, "working_set", json!({ "limit": 32 }));
        let payload: Value = serde_json::from_str(&content_text(&result)).unwrap();

        assert_eq!(payload["items"].as_array().unwrap().len(), 1);
        assert!(payload["items"][0]["attention"].is_number());
        assert!(payload["items"][0]["observation_count"].is_number());
        assert!(engine
            .telemetry_snapshot(20)
            .unwrap()
            .by_name
            .iter()
            .any(|metric| metric.name == "working_set" && metric.calls == 1));

        let schema = list()
            .into_iter()
            .find(|tool| tool["name"] == "working_set")
            .unwrap();
        assert_eq!(schema["inputSchema"]["properties"]["limit"]["maximum"], 32);
    }

    #[test]
    fn working_set_errors_without_configured_agent() {
        let engine = MindLeak::open_in_memory().unwrap();
        let error = call(&engine, &json!({ "name": "working_set", "arguments": {} })).unwrap_err();
        assert!(error.contains("MINDLEAK_AGENT"));
    }

    #[test]
    fn lifecycle_tools_export_backup_and_confirm_reset() {
        let engine = MindLeak::open_in_memory().unwrap();
        call_ok(
            &engine,
            "ingest_file",
            json!({ "path": "src/lib.rs", "content": "pub fn mindleak() {}" }),
        );

        let export: Value =
            serde_json::from_str(&content_text(&call_ok(&engine, "export_graph", json!({}))))
                .unwrap();
        assert!(export["nodes"]
            .as_array()
            .unwrap()
            .iter()
            .any(|node| node["id"] == "artifact:src/lib.rs"));

        let path =
            std::env::temp_dir().join(format!("mindleak-mcp-backup-{}.db", std::process::id()));
        let _ = std::fs::remove_file(&path);
        call_ok(
            &engine,
            "backup_database",
            json!({ "path": path.to_str().unwrap() }),
        );
        assert!(path.exists());
        std::fs::remove_file(path).unwrap();

        let rejected = call(
            &engine,
            &json!({ "name": "reset_database", "arguments": { "confirm": "yes" } }),
        )
        .unwrap_err();
        assert!(rejected.contains("RESET MINDLEAK"));
        let reset = call_ok(
            &engine,
            "reset_database",
            json!({ "confirm": "RESET MINDLEAK" }),
        );
        assert!(content_text(&reset).contains("nodes_removed"));
        assert_eq!(engine.counts().unwrap(), (0, 0));
    }

    #[test]
    fn evidence_for_returns_attributed_mutation_provenance() {
        let engine = MindLeak::open_in_memory()
            .unwrap()
            .with_agent(Some("agent-a".into()));
        call_ok(
            &engine,
            "ingest_execution",
            json!({
                "command": "cargo check",
                "exit_code": 0,
                "changed_files": ["src/lib.rs"],
                "timestamp": 100
            }),
        );

        let result = call_ok(
            &engine,
            "evidence_for",
            json!({
                "task_id": "task:proof",
                "agent_id": "agent-a",
                "started_at": 90,
                "ended_at": 110
            }),
        );
        let evidence: Value = serde_json::from_str(&content_text(&result)).unwrap();
        assert_eq!(evidence["schema_version"], 1);
        assert_eq!(evidence["task_id"], "task:proof");
        assert_eq!(evidence["changed_node_ids"][0], "artifact:src/lib.rs");
        assert_eq!(
            evidence["successful_execution_ids"]
                .as_array()
                .unwrap()
                .len(),
            1
        );
        assert!(evidence["provenance"]
            .as_array()
            .unwrap()
            .iter()
            .any(|fact| fact["relation"] == "modified"));
    }
}
